  { id: '#577', login: 'S687', name: '123-4567-890-1234', modifyDate: '12/05/2025 02:26 PM', ticket: 'SCTASK0000000', platform: 'VOCALCOM' },
  { id: '#578', login: 'S891', name: '234-5678-901-2345', modifyDate: '12/05/2025 02:26 PM', ticket: 'SCTASK0000000', platform: 'UTIBA_2TMV' },
  { id: '#579', login: 'S165', name: '958-4030-182-0187', modifyDate: '12/05/2025 02:26 PM', ticket: 'SCTASK0000000', platform: '' },
  { id: '#580', login: 'S165', name: '345-6789-012-3456', modifyDate: '12/05/2025 02:26 PM', ticket: 'SCTASK0000000', platform: '' },
